# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory team collaboration backend implementing users,
projects, tasks, messaging, performance analytics, and report export.

Standard library only, ASCII only. Python 3.12.
"""

from __future__ import annotations

import csv
import io
from datetime import datetime
from enum import Enum
import threading
from typing import Any, Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base error for all collaboration manager failures."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# Sentinel used to distinguish "argument not provided" from an explicit None.
_UNSET = object()


# ---------------------------------------------------------------------------
# Data classes
# ---------------------------------------------------------------------------
class Attachment:
    """A file attached to a message."""

    def __init__(self, filename: str, size: int, uploaded_by: int,
                 uploaded_at: datetime) -> None:
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at

    def clone(self) -> "Attachment":
        return Attachment(self.filename, self.size, self.uploaded_by,
                          self.uploaded_at)


class User:
    """A registered user."""

    def __init__(self, id: int, username: str, email: str, role: UserRole,
                 created_at: datetime) -> None:
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at

    def clone(self) -> "User":
        return User(self.id, self.username, self.email, self.role,
                    self.created_at)


class Project:
    """A project owned by a user."""

    def __init__(self, id: int, name: str, start_date: datetime,
                 end_date: datetime, owner_id: int, description: str,
                 created_at: datetime) -> None:
        self.id = id
        self.name = name
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.description = description
        self.created_at = created_at

    def clone(self) -> "Project":
        return Project(self.id, self.name, self.start_date, self.end_date,
                       self.owner_id, self.description, self.created_at)


class Task:
    """A unit of work within a project."""

    def __init__(self, id: int, project_id: int, title: str,
                 status: TaskStatus, assignee_id: Optional[int],
                 deadline: Optional[datetime], started_at: Optional[datetime],
                 completed_at: Optional[datetime],
                 created_at: datetime) -> None:
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = started_at
        self.completed_at = completed_at
        self.created_at = created_at

    def clone(self) -> "Task":
        return Task(self.id, self.project_id, self.title, self.status,
                    self.assignee_id, self.deadline, self.started_at,
                    self.completed_at, self.created_at)


class Message:
    """A message posted to a project or a task."""

    def __init__(self, id: int, author_id: int, body: str,
                 project_id: Optional[int], task_id: Optional[int],
                 parent_id: Optional[int], attachments: List[Attachment],
                 created_at: datetime,
                 edited_at: Optional[datetime]) -> None:
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments
        self.created_at = created_at
        self.edited_at = edited_at

    def clone(self) -> "Message":
        return Message(
            self.id, self.author_id, self.body, self.project_id, self.task_id,
            self.parent_id, [a.clone() for a in self.attachments],
            self.created_at, self.edited_at,
        )


class Rating:
    """A peer rating submitted for a user."""

    def __init__(self, id: int, rater_id: int, ratee_id: int, score: int,
                 feedback: str, task_id: Optional[int],
                 created_at: datetime) -> None:
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at

    def clone(self) -> "Rating":
        return Rating(self.id, self.rater_id, self.ratee_id, self.score,
                      self.feedback, self.task_id, self.created_at)


# ---------------------------------------------------------------------------
# Shared store
# ---------------------------------------------------------------------------
class _Store:
    """A lightweight item container that shares a single global lock.

    All stores exposed by the manager share the SAME RLock instance so that
    concurrency tests can assert lock identity and so that nested manager
    operations are safe (RLock is reentrant).
    """

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self._items: Dict[int, Any] = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Thread-safe in-memory team collaboration manager."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now

        # One shared reentrant lock guards all state.
        self._lock = threading.RLock()

        # Sub-stores all share the same lock object (identity matters).
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # Single global id counter shared across all entity types.
        self._next_id = 1

        # Uniqueness indexes for users.
        self._usernames: Dict[str, int] = {}
        self._emails: Dict[str, int] = {}

        # Relationship indexes.
        self._project_tasks: Dict[int, set] = {}
        self._assignee_tasks: Dict[int, set] = {}
        self._project_messages: Dict[int, set] = {}
        self._task_messages: Dict[int, set] = {}
        self._ratee_ratings: Dict[int, set] = {}

    # -- internal helpers (assume lock held) -------------------------------
    def _alloc_id(self) -> int:
        new_id = self._next_id
        self._next_id += 1
        return new_id

    def _require_user(self, user_id: int) -> User:
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, msg_id: int) -> Message:
        msg = self.messages._items.get(msg_id)
        if msg is None:
            raise NotFoundError("Message {0} not found".format(msg_id))
        return msg

    @staticmethod
    def _validate_email(email: str) -> str:
        if email is None:
            raise ValidationError("Email is required")
        email = email.strip()
        if not email:
            raise ValidationError("Email is required")
        if "@" not in email:
            raise ValidationError("Email must contain '@'")
        return email

    # ------------------------------------------------------------------
    # Users
    # ------------------------------------------------------------------
    def register_user(self, username: str, email: str,
                      role: UserRole = UserRole.MEMBER) -> User:
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")
        if username is None:
            raise ValidationError("Username is required")
        username = username.strip()
        if not username:
            raise ValidationError("Username is required")
        email = self._validate_email(email)
        with self._lock:
            if username in self._usernames:
                raise DuplicateError("Username already exists")
            if email in self._emails:
                raise DuplicateError("Email already exists")
            user = User(self._alloc_id(), username, email, role, self._now())
            self.users._items[user.id] = user
            self._usernames[username] = user.id
            self._emails[email] = user.id
            return user.clone()

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return self._require_user(user_id).clone()

    def list_users(self) -> List[User]:
        with self._lock:
            return [self.users._items[i].clone()
                    for i in sorted(self.users._items)]

    def update_user(self, user_id: int, username: Any = _UNSET,
                    email: Any = _UNSET, role: Any = _UNSET) -> User:
        with self._lock:
            user = self._require_user(user_id)

            new_username = user.username
            if username is not _UNSET and username is not None:
                candidate = username.strip()
                if not candidate:
                    raise ValidationError("Username is required")
                existing = self._usernames.get(candidate)
                if existing is not None and existing != user_id:
                    raise DuplicateError("Username already exists")
                new_username = candidate

            new_email = user.email
            if email is not _UNSET and email is not None:
                candidate_email = self._validate_email(email)
                existing = self._emails.get(candidate_email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("Email already exists")
                new_email = candidate_email

            new_role = user.role
            if role is not _UNSET and role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            # Apply changes, keeping uniqueness indexes consistent.
            if new_username != user.username:
                del self._usernames[user.username]
                self._usernames[new_username] = user_id
                user.username = new_username
            if new_email != user.email:
                del self._emails[user.email]
                self._emails[new_email] = user_id
                user.email = new_email
            user.role = new_role
            return user.clone()

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self._require_user(user_id)
            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("User owns one or more projects")
            for task_id in self._assignee_tasks.get(user_id, set()):
                task = self.tasks._items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("User has open assigned tasks")
            del self.users._items[user_id]
            self._usernames.pop(user.username, None)
            self._emails.pop(user.email, None)
            self._assignee_tasks.pop(user_id, None)

    # ------------------------------------------------------------------
    # Projects
    # ------------------------------------------------------------------
    def create_project(self, name: str, start_date: datetime,
                       end_date: datetime, owner_id: int,
                       description: str = "") -> Project:
        with self._lock:
            self._require_user(owner_id)
            if name is None or not name.strip():
                raise ValidationError("Project name is required")
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")
            project = Project(self._alloc_id(), name.strip(), start_date,
                              end_date, owner_id, description, self._now())
            self.projects._items[project.id] = project
            self._project_tasks[project.id] = set()
            self._project_messages[project.id] = set()
            return project.clone()

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return self._require_project(project_id).clone()

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [self.projects._items[i].clone()
                    for i in sorted(self.projects._items)]

    def update_project(self, project_id: int, name: Any = _UNSET,
                       start_date: Any = _UNSET, end_date: Any = _UNSET,
                       description: Any = _UNSET) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name
            if name is not _UNSET and name is not None:
                if not name.strip():
                    raise ValidationError("Project name is required")
                new_name = name.strip()

            new_start = project.start_date
            if start_date is not _UNSET and start_date is not None:
                new_start = start_date

            new_end = project.end_date
            if end_date is not _UNSET and end_date is not None:
                new_end = end_date

            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not _UNSET and description is not None:
                project.description = description
            return project.clone()

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)

            # Cascade delete tasks (and their messages + assignee index).
            for task_id in list(self._project_tasks.get(project_id, set())):
                self._purge_task(task_id)

            # Cascade delete project-targeted messages.
            for msg_id in list(self._project_messages.get(project_id, set())):
                self._purge_message(msg_id)

            self._project_tasks.pop(project_id, None)
            self._project_messages.pop(project_id, None)
            del self.projects._items[project_id]

    def _purge_task(self, task_id: int) -> None:
        """Remove a task and all of its dependent state (lock held)."""
        task = self.tasks._items.get(task_id)
        if task is None:
            return
        self._project_tasks.get(task.project_id, set()).discard(task_id)
        if task.assignee_id is not None:
            self._assignee_tasks.get(task.assignee_id, set()).discard(task_id)
        for msg_id in list(self._task_messages.get(task_id, set())):
            self._purge_message(msg_id)
        self._task_messages.pop(task_id, None)
        del self.tasks._items[task_id]

    def _purge_message(self, msg_id: int) -> None:
        """Remove a message and its index entries (lock held)."""
        msg = self.messages._items.get(msg_id)
        if msg is None:
            return
        if msg.project_id is not None:
            self._project_messages.get(msg.project_id, set()).discard(msg_id)
        if msg.task_id is not None:
            self._task_messages.get(msg.task_id, set()).discard(msg_id)
        del self.messages._items[msg_id]

    # ------------------------------------------------------------------
    # Tasks
    # ------------------------------------------------------------------
    def create_task(self, project_id: int, title: str,
                    assignee_id: Optional[int] = None,
                    deadline: Optional[datetime] = None) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if assignee_id is not None:
                self._require_user(assignee_id)
            if title is None or not title.strip():
                raise ValidationError("Task title is required")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            task = Task(self._alloc_id(), project_id, title.strip(),
                        TaskStatus.NOT_STARTED, assignee_id, deadline,
                        None, None, self._now())
            self.tasks._items[task.id] = task
            self._project_tasks.setdefault(project_id, set()).add(task.id)
            if assignee_id is not None:
                self._assignee_tasks.setdefault(assignee_id, set()).add(task.id)
            return task.clone()

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return self._require_task(task_id).clone()

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self._project_tasks.get(project_id, set()))
            return [self.tasks._items[i].clone() for i in ids]

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self._assignee_tasks.get(user_id, set()))
            return [self.tasks._items[i].clone() for i in ids]

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            if task.assignee_id is not None:
                self._assignee_tasks.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = assignee_id
            self._assignee_tasks.setdefault(assignee_id, set()).add(task_id)
            return task.clone()

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if task.assignee_id is not None:
                self._assignee_tasks.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = None
            return task.clone()

    def set_deadline(self, task_id: int,
                     deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return task.clone()

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return task.clone()

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id: int, body: str,
                     project_id: Optional[int] = None,
                     task_id: Optional[int] = None,
                     parent_id: Optional[int] = None,
                     attachments: Optional[List[Tuple[str, bytes]]] = None
                     ) -> Message:
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "Exactly one of project_id or task_id is required")
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)

            body = body if body is not None else ""
            has_attachments = bool(attachments)
            if not body.strip() and not has_attachments:
                raise ValidationError("Message body or attachment is required")

            if parent_id is not None:
                self._require_message(parent_id)

            now = self._now()
            built: List[Attachment] = []
            if attachments:
                for filename, data in attachments:
                    built.append(Attachment(filename, len(data), author_id, now))

            msg = Message(self._alloc_id(), author_id, body, project_id,
                          task_id, parent_id, built, now, None)
            self.messages._items[msg.id] = msg
            if project_id is not None:
                self._project_messages.setdefault(project_id, set()).add(msg.id)
            if task_id is not None:
                self._task_messages.setdefault(task_id, set()).add(msg.id)
            return msg.clone()

    def edit_message(self, msg_id: int, editor_id: int,
                     new_body: str) -> Message:
        with self._lock:
            msg = self._require_message(msg_id)
            if editor_id != msg.author_id:
                raise AuthorizationError("Only the author may edit a message")
            if new_body is None or not new_body.strip():
                raise ValidationError("Message body is required")
            msg.body = new_body
            msg.edited_at = self._now()
            return msg.clone()

    def add_attachment(self, msg_id: int, user_id: int, filename: str,
                       data: bytes) -> Message:
        with self._lock:
            msg = self._require_message(msg_id)
            if user_id != msg.author_id:
                raise AuthorizationError("Only the author may add attachments")
            if filename is None or not filename.strip():
                raise ValidationError("Filename is required")
            msg.attachments.append(
                Attachment(filename, len(data), user_id, self._now()))
            return msg.clone()

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self._project_messages.get(project_id, set()))
            return [self.messages._items[i].clone() for i in ids]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self._task_messages.get(task_id, set()))
            return [self.messages._items[i].clone() for i in ids]

    def delete_message(self, msg_id: int, user_id: int) -> None:
        with self._lock:
            msg = self._require_message(msg_id)
            if user_id != msg.author_id:
                raise AuthorizationError("Only the author may delete a message")
            self._purge_message(msg_id)

    # ------------------------------------------------------------------
    # Performance
    # ------------------------------------------------------------------
    def submit_rating(self, rater_id: int, ratee_id: int, score: int,
                      feedback: str = "",
                      task_id: Optional[int] = None) -> Rating:
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool) \
                    or score < 1 or score > 5:
                raise ValidationError("score must be an int in 1..5")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("Cannot rate yourself")
            if task_id is not None:
                self._require_task(task_id)
            rating = Rating(self._alloc_id(), rater_id, ratee_id, score,
                            feedback, task_id, self._now())
            self.performance._items[rating.id] = rating
            self._ratee_ratings.setdefault(ratee_id, set()).add(rating.id)
            return rating.clone()

    def _user_tasks(self, user_id: int) -> List[Task]:
        ids = sorted(self._assignee_tasks.get(user_id, set()))
        return [self.tasks._items[i] for i in ids if i in self.tasks._items]

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks
                            if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = []
            for t in self._user_tasks(user_id):
                if t.status == TaskStatus.COMPLETED and \
                        t.started_at is not None and t.completed_at is not None:
                    durations.append(
                        (t.completed_at - t.started_at).total_seconds())
            if not durations:
                return None
            return sum(durations) / len(durations)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        ids = sorted(self._ratee_ratings.get(user_id, set()))
        return [self.performance._items[i] for i in ids
                if i in self.performance._items]

    def get_ratings_summary(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [r.clone() for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = in_progress = not_started = 0
            for t in tasks:
                s = t.status
                if s == TaskStatus.COMPLETED:
                    completed += 1
                elif s == TaskStatus.IN_PROGRESS:
                    in_progress += 1
                else:
                    not_started += 1
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (sum(r.score for r in ratings) / rating_count) \
                if rating_count else 0.0
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": self._avg_completion(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    @staticmethod
    def _avg_completion(tasks: List[Task]) -> Optional[float]:
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def _user_stats(self, user_id: int, tasks: List[Task]) -> Dict[str, Any]:
        """Compute per-user statistics over the supplied task list."""
        total = len(tasks)
        completed = in_progress = not_started = 0
        for t in tasks:
            s = t.status
            if s == TaskStatus.COMPLETED:
                completed += 1
            elif s == TaskStatus.IN_PROGRESS:
                in_progress += 1
            else:
                not_started += 1
        ratings = self._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (sum(r.score for r in ratings) / rating_count) \
            if rating_count else 0.0
        user = self.users._items.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user else None,
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": self._avg_completion(tasks),
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def project_progress_report(self, project_id: int) -> Dict[str, Any]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self._project_tasks.get(project_id, set()))
            tasks = [self.tasks._items[i] for i in ids]
            now = self._now()

            status_counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            overdue = 0
            per_assignee_tasks: Dict[int, List[Task]] = {}
            for t in tasks:
                status_counts[t.status.value] += 1
                if t.deadline is not None and t.deadline < now \
                        and t.status != TaskStatus.COMPLETED:
                    overdue += 1
                if t.assignee_id is not None:
                    per_assignee_tasks.setdefault(t.assignee_id, []).append(t)

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            per_assignee = {
                uid: self._user_stats(uid, alist)
                for uid, alist in per_assignee_tasks.items()
            }
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self,
                                project_id: Optional[int] = None
                                ) -> Dict[str, Any]:
        with self._lock:
            rows: List[Dict[str, Any]] = []
            if project_id is None:
                for uid in sorted(self.users._items):
                    rows.append(self._user_stats(uid, self._user_tasks(uid)))
            else:
                self._require_project(project_id)
                task_ids = sorted(self._project_tasks.get(project_id, set()))
                tasks = [self.tasks._items[i] for i in task_ids]
                by_assignee: Dict[int, List[Task]] = {}
                for t in tasks:
                    if t.assignee_id is not None:
                        by_assignee.setdefault(t.assignee_id, []).append(t)
                for uid in sorted(by_assignee):
                    rows.append(self._user_stats(uid, by_assignee[uid]))
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self,
                                      user_id: int) -> Dict[str, Any]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            task_dicts = []
            completed = 0
            for t in tasks:
                if t.status == TaskStatus.COMPLETED:
                    completed += 1
                duration = None
                if t.started_at is not None and t.completed_at is not None:
                    duration = (t.completed_at - t.started_at).total_seconds()
                task_dicts.append({
                    "task_id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline.isoformat()
                    if t.deadline is not None else None,
                    "started_at": t.started_at.isoformat()
                    if t.started_at is not None else None,
                    "completed_at": t.completed_at.isoformat()
                    if t.completed_at is not None else None,
                    "completion_time": duration,
                })
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "tasks": task_dicts,
            }

    # ------------------------------------------------------------------
    # Export
    # ------------------------------------------------------------------
    def export_report(self, report: Dict[str, Any],
                      fmt: ReportFormat) -> Any:
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    @staticmethod
    def _export_csv(report: Dict[str, Any]) -> str:
        output = io.StringIO()
        rows = report.get("rows")
        if isinstance(rows, list) and rows and \
                all(isinstance(r, dict) for r in rows):
            # Build header as the ordered union of all row keys.
            header: List[str] = []
            seen = set()
            for row in rows:
                for key in row.keys():
                    if key not in seen:
                        seen.add(key)
                        header.append(key)
            writer = csv.DictWriter(output, fieldnames=header,
                                    extrasaction="ignore")
            writer.writeheader()
            for row in rows:
                writer.writerow({k: TeamCollaborationManager._stringify(row.get(k))
                                 for k in header})
        else:
            writer = csv.writer(output)
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key,
                                 TeamCollaborationManager._stringify(value)])
        return output.getvalue()

    @staticmethod
    def _stringify(value: Any) -> str:
        if value is None:
            return ""
        if isinstance(value, (dict, list)):
            return str(value)
        return str(value)

    @staticmethod
    def _export_pdf(report: Dict[str, Any]) -> bytes:
        # Render the report dict as plain text lines inside a minimal,
        # structurally valid single-page PDF.
        lines: List[str] = []
        for key, value in report.items():
            text = "{0}: {1}".format(key,
                                     TeamCollaborationManager._stringify(value))
            # Escape PDF special characters and keep ASCII only.
            text = text.replace("\\", "\\\\").replace("(", "\\(") \
                       .replace(")", "\\)")
            text = text.encode("ascii", "replace").decode("ascii")
            lines.append(text)
        if not lines:
            lines.append("(empty report)")

        content_parts = ["BT", "/F1 12 Tf", "1 0 0 1 50 750 Tm", "14 TL"]
        for i, line in enumerate(lines):
            if i > 0:
                content_parts.append("T*")
            content_parts.append("({0}) Tj".format(line))
        content_parts.append("ET")
        content_stream = "\n".join(content_parts).encode("ascii")

        objects: List[bytes] = []
        objects.append(b"<< /Type /Catalog /Pages 2 0 R >>")
        objects.append(b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
        objects.append(
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>")
        objects.append(
            b"<< /Length " + str(len(content_stream)).encode("ascii") +
            b" >>\nstream\n" + content_stream + b"\nendstream")
        objects.append(
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>")

        pdf = io.BytesIO()
        pdf.write(b"%PDF-1.4\n")
        offsets = []
        for i, obj in enumerate(objects, start=1):
            offsets.append(pdf.tell())
            pdf.write(str(i).encode("ascii") + b" 0 obj\n")
            pdf.write(obj)
            pdf.write(b"\nendobj\n")

        xref_pos = pdf.tell()
        count = len(objects) + 1
        pdf.write(b"xref\n")
        pdf.write(b"0 " + str(count).encode("ascii") + b"\n")
        pdf.write(b"0000000000 65535 f \n")
        for off in offsets:
            pdf.write("{0:010d} 00000 n \n".format(off).encode("ascii"))
        pdf.write(b"trailer\n")
        pdf.write(b"<< /Size " + str(count).encode("ascii") +
                  b" /Root 1 0 R >>\n")
        pdf.write(b"startxref\n")
        pdf.write(str(xref_pos).encode("ascii") + b"\n")
        pdf.write(b"%%EOF")
        return pdf.getvalue()
